/* ============================================================
 * globex_i18n.js  —  Globex OS shared internationalization layer
 * ------------------------------------------------------------
 * Languages: en (default, LTR), ar (RTL), fa (RTL)
 * Used by login.html, index.html, and EVERY unit page so the
 * whole system is trilingual from the first line — never retrofitted.
 *
 * USAGE (add once, before your page script):
 *   <script src="./globex_i18n.js"></script>
 *
 * Then in your page:
 *   GX_I18N.init();                  // applies saved/default language + dir
 *   GX_I18N.t('dashboard');          // -> "Dashboard" / "لوحة القيادة" / "داشبورد"
 *   GX_I18N.setLang('ar');           // switch language (persists + flips dir)
 *   GX_I18N.applyDOM();              // translate any element with data-i18n="key"
 *   GX_I18N.num(25950000);           // localized number
 *   GX_I18N.date('2026-06-22');      // localized date
 *   GX_I18N.onChange(fn);            // run fn whenever language changes
 *
 * To add a label: add the same key under en/ar/fa in DICT below.
 * To make a unit trilingual: give its label/mission three keys here,
 *   or pass a {en,ar,fa} object to GX_I18N.pick(obj).
 * ============================================================ */
