    // Outbound sequence / cadence builder
    unit_sequence:   { en:"Outbound sequences", ar:"تسلسلات التواصل", fa:"توالیِ خروجی" },
    seq_intro:       { en:"Build multi-step outreach cadences — email, LinkedIn, WhatsApp, call — with a day-delay per step. Enroll prospects and move them through. Signal-personalized, consent-gated, and spaced so you never spam. Sequencing is what turns a one-off message into a system.", ar:"بناء تسلسلات متعددة الخطوات.", fa:"کدنسِ چندمرحله‌ایِ ارتباط بساز — ایمیل، لینکدین، واتساپ، تماس — با فاصله‌ی روزِ هر مرحله. مخاطب‌ها را ثبت کن و پیش ببر. سیگنال‌محور، مشروط به رضایت، و فاصله‌دار تا هرگز اسپم نشود. توالی همان چیزی است که یک پیامِ تکی را به سیستم تبدیل می‌کند." },
