    // Sales forecast & pipeline velocity
    unit_forecast:   { en:"Forecast & velocity", ar:"التنبؤ والسرعة", fa:"پیش‌بینی و سرعتِ پایپ‌لاین" },
    fc_intro:        { en:"Predict revenue from your real pipeline: weight each open deal by its stage probability, see the committed / best-case / weighted forecast, and measure pipeline velocity — how fast value moves to closed. Built from actual deals, not guesses.", ar:"تنبؤ بالإيرادات.", fa:"درآمد را از پایپ‌لاینِ واقعی پیش‌بینی کن: هر معامله‌ی باز را با احتمالِ مرحله‌اش وزن بده، پیش‌بینیِ قطعی / خوش‌بینانه / وزنی را ببین، و سرعتِ پایپ‌لاین را بسنج — اینکه ارزش چقدر سریع به بسته‌شدن می‌رسد. از معامله‌های واقعی، نه حدس." },
