    fc_pipeline:     { en:"Open pipeline", ar:"خط الأنابيب", fa:"پایپ‌لاینِ باز" },
    fc_bystage:      { en:"By stage", ar:"حسب المرحلة", fa:"به تفکیکِ مرحله" },
