    fc_value:        { en:"Value", ar:"القيمة", fa:"ارزش" },
    fc_prob:         { en:"Win prob.", ar:"احتمال", fa:"احتمالِ بُرد" },
    fc_weighted_col: { en:"Weighted", ar:"مرجح", fa:"وزنی" },
    fc_velocity:     { en:"Pipeline velocity", ar:"سرعة الأنابيب", fa:"سرعتِ پایپ‌لاین" },
    fc_vel_explain:  { en:"Velocity = (open deals × avg value × win-rate) ÷ avg sales-cycle days. It's the revenue your pipeline generates per day.", ar:"السرعة = ...", fa:"سرعت = (تعدادِ معامله‌ی باز × میانگینِ ارزش × نرخِ بُرد) ÷ میانگینِ روزهای چرخه‌ی فروش. یعنی درآمدی که پایپ‌لاین در روز تولید می‌کند." },
